import React, { useState, useEffect } from 'react';
import './App.css';

function App() {
    const [tokenIds, setTokenIds] = useState([]);

    useEffect(() => {
        fetch('/token-ids')
            .then(response => response.json())
            .then(data => setTokenIds(data))
            .catch(error => console.error('Error:', error));
    }, []);
    const [selectedAsset, setSelectedAsset] = useState('');
    // State for storing the image URL
    const [imageUrl, setImageUrl] = useState('');

    const handleTokenChange = (event) => {
        setTokenIds(event.target.value);
    };

    const handleAssetChange = (event) => {
        setSelectedAsset(event.target.value);
    };

    const handleSubmit = () => {
        fetch(`/get-asset?tokenId=${tokenIds}&assetType=${selectedAsset}`)
            .then(response => {
        if (!response.ok) {
            throw new Error('Network response was not ok ' + response.statusText);
        }
        return response.json();
    })
    .then(data => {
        console.log('Received data:', data);
        if (data.image_url) {
            setImageUrl(data.image_url);
        }
    })
    .catch(error => {
        console.error('Error:', error);
    });
  };


  return (
    <div className="App">
        <header className="App-header">
            <select value={tokenId} onChange={handleTokenChange}>
                <option value="">Select Token ID</option>
                {tokenIds.map(id => (
                    <option key={id} value={id}>{id}</option>
                ))}
            </select>
                <select value={selectedAsset} onChange={handleAssetChange}>
                    <option value="">Select an Asset</option>
                    <option value="gm">gm</option>
                    <option value="cheers">cheers</option>
                    <option value="peace">peace</option>
                </select>
                <button onClick={handleSubmit}>Submit</button>
                {/* Placeholder for asset display */}
                <div id="asset-display">
                    {imageUrl && <img src={imageUrl} alt="Processed NFT" />}
                </div>

            </header>
        </div>
    );
}

export default App;
